import base64
import io
import shutil
import subprocess
import tarfile
import tempfile
from pathlib import Path

PAYLOAD = ""


def main() -> None:
    repo_root = Path(__file__).resolve().parents[2]
    with tempfile.TemporaryDirectory(prefix="top-shot-payload-") as tmp_name:
        tmp = Path(tmp_name)
        data = base64.b64decode(PAYLOAD)
        with tarfile.open(fileobj=io.BytesIO(data), mode="r:gz") as archive:
            archive.extractall(tmp)
        subprocess.run(["patch", "-p1", "-i", str(tmp / "all.patch")], cwd=repo_root, check=True)
        source = tmp / "topshot-snapshot" / "top-shot" / "tests" / "renderPipelineSmoke.js"
        destination = repo_root / "top-shot" / "tests" / "renderPipelineSmoke.js"
        destination.parent.mkdir(parents=True, exist_ok=True)
        shutil.copyfile(source, destination)


if __name__ == "__main__":
    main()
